mapper.select:
SELECT COUNT(DISTINCT m.cltr_no)
FROM auction_master m
LEFT JOIN (
SELECT cltr_no, ROW_NUMBER() OVER(PARTITION BY cltr_no ORDER BY pbct_cls_dtm DESC) as rn,
min_bid_prc, pbct_cls_dtm
FROM auction_history
) lh ON m.cltr_no = lh.cltr_no AND lh.rn = 1


        MATCH(m.cln_ldnm_adrs, m.cln_nmrd_adrs, m.cltr_nm) AGAINST(#{keyword} IN NATURAL LANGUAGE MODE)


        AND m.cln_ldnm_adrs LIKE CONCAT(#{region}, '%')


        AND lh.min_bid_prc >= #{priceFrom}


        AND lh.min_bid_prc <= #{priceTo}


        AND DATE(lh.pbct_cls_dtm) >= #{dateFrom}


        AND DATE(lh.pbct_cls_dtm) <= #{dateTo}

SELECT m.cltr_no, m.cltr_nm, m.ctgr_full_nm, m.cln_ldnm_adrs, m.cln_nmrd_adrs, m.latitude, m.longitude,
       lh.min_bid_prc, lh.apsl_ases_avg_amt, lh.pbct_begn_dtm, lh.pbct_cls_dtm, lh.pbct_cltr_stat_nm
FROM auction_master m
LEFT JOIN (
    SELECT cltr_no, ROW_NUMBER() OVER(PARTITION BY cltr_no ORDER BY pbct_cls_dtm DESC) as rn,
           min_bid_prc, apsl_ases_avg_amt, pbct_begn_dtm, pbct_cls_dtm, pbct_cltr_stat_nm
    FROM auction_history
) lh ON m.cltr_no = lh.cltr_no AND lh.rn = 1


        MATCH(m.cln_ldnm_adrs, m.cln_nmrd_adrs, m.cltr_nm) AGAINST(#{keyword} IN NATURAL LANGUAGE MODE)


        AND m.cln_ldnm_adrs LIKE CONCAT(#{region}, '%')


        AND lh.min_bid_prc >= #{priceFrom}


        AND lh.min_bid_prc <= #{priceTo}


        AND DATE(lh.pbct_cls_dtm) >= #{dateFrom}


        AND DATE(lh.pbct_cls_dtm) <= #{dateTo}


ORDER BY lh.pbct_cls_dtm DESC
LIMIT #{limit} OFFSET #{offset}
